window.__QUIZ_DATA__=[{"id":"objective>Mathematics>2008>1","subject":"Mathematics","year":"2008","type":"Objective","topic":"NUMBER AND NUMERATION : PERCENTAGES","question":"If x% of 240 equals 12. Find x.","images":[],"options":{"A":"x = 1","B":"x = 3","C":"x = 5","D":"x = 7"},"answer":"C","explanation":"Given: x% of 240 = 12   \u2234x100\u00d7240=12  \u2234x=1200240=5","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2008>2","subject":"Mathematics","year":"2008","type":"Objective","topic":"NUMBER AND NUMERATION : LAWS OF INDICES","question":"Evaluate(3.2)2 - (4.8)23.2 + 4.8","images":[],"options":{"A":"-0.08","B":"-1.60","C":"-10.24","D":"-12.80"},"answer":"B","explanation":"Given: To evaluate(3.2)2 - (4.8)23.2 + 4.8  Recall that: a2 - b2 = (a + b)(a - b)   \u2234(3.2)2-(4.8)23.2+4.8=(3.2+4.8)(3.2-4.8)3.2+4.8   = 3.2 - 4.8 = -1.6","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2008>3","subject":"Mathematics","year":"2008","type":"Objective","topic":"NUMBER AND NUMERATION : NUMBERS IN STANDARD FORM-SCIENTIFIC NOTATION","question":"Find the product of 0.0409 and 0.0021 leaving your answer in the standard form.","images":[],"options":{"A":"8.6 \u00d7 10-6","B":"8.6 \u00d7 10-5","C":"8.6 \u00d7 10-4","D":"8.6 \u00d7 105"},"answer":"B","explanation":"Given: To find the product of 0.0409 and 0.0021 in standard form.   = 0.0409 \u00d7 0.0021   = 0.00008589   = 8.589 \u00d7 10-5    \u2248 8.6 \u00d7 10-5","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2008>4","subject":"Mathematics","year":"2008","type":"Objective","topic":"ALGEBRAIC PROCESSES : EXPANSION AND FACTORISATION","question":"Simplify50+10&radic;2&nbsp;","images":[],"options":{"A":"10","B":"10&radic;2&nbsp;","C":"20","D":"20&radic;2&nbsp;"},"answer":"B","explanation":"Given: Tosimply&radic;50&nbsp;+10&radic;2&nbsp;  =&radic;50&nbsp;+10&radic;2&nbsp;2   = &radic;50&nbsp; + 5&radic;2&nbsp;   = 5&radic;2&nbsp; + 5&radic;2&nbsp; = 10&radic;2&nbsp;","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2008>5","subject":"Mathematics","year":"2008","type":"Objective","topic":"NUMBER AND NUMERATION : SIMPLE INTEREST AND COMPOUND INTEREST","question":"P naira invested for 4 years at r % simple interest per annum yields 0.36 P naira interest. Find the value of r.","images":[],"options":{"A":"119","B":"149","C":"9","D":"11"},"answer":"C","explanation":"Given:  1. The principal, P = P naira  2. The time, T = 4 years  3. The rate, R = r%  4. The simple interest, S.I = 0.36P  Recall that: S.I=PRT100  \u22340.36P=P\u00d7R\u00d74100  36P = 4PR  R = 9%","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2008>6","subject":"Mathematics","year":"2008","type":"Objective","topic":"NUMBER AND NUMERATION : NUMBER BASES","question":"Convert 425 to a base three numeral.","images":[],"options":{"A":"2013","B":"2103","C":"2113","D":"2223"},"answer":"C","explanation":"Given: To convert 425 to a base three numeral   Since 42 is not in base 10, it has to be in base 10 first.  425 in base 10 = 4 \u00d7 51 + 2 \u00d7 50  20 + 2 = 2210  Divide 2210 by the required base (base 3)  32237 r 1 \u219132 r 1 \u21910 r 2 \u2191  \u2234 425 = 2210 = 2113  \u2234 425 in base 3 = 2113","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2008>7","subject":"Mathematics","year":"2008","type":"Objective","topic":"NUMBER AND NUMERATION : PROFIT AND LOSS","question":"A trader bought 100 tubers of yam at 5 for \u20a6350.00. She sold them in sets of 4 for \u20a6290.00. Find her gain percent.","images":[],"options":{"A":"3.6%","B":"3.5%","C":"3.4%","D":"2.5%"},"answer":"A","explanation":"Given:  The total tubers bought = 100  Rate per 5 tubers  = \u20a6350  \u2234 For 100 tubers, wehave;3505\u00d7100  = \u20a67,000  \u2234 Her cost price = \u20a67,000  The rate per 4 tubers = \u20a6290  \u2234 For 100 tubers, wehave;2904\u00d7100   = \u20a67250  \u2234 Her selling price = \u20a67250  \u2192 She has made a gain since her selling price is greater than her cost price.   %gain=7250 - 70007000\u00d7100   2507000\u00d7100=25070=257=3.6%","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2008>8","subject":"Mathematics","year":"2008","type":"Objective","topic":"ALGEBRAIC PROCESSES : SIMULTANEOUS LINEAR EQUATIONS IN TWO VARIABLES","question":"If p - 2g + 1 = g + 3p and p - 2 = 0, find g.","images":[],"options":{"A":"-2","B":"-1","C":"1","D":"2"},"answer":"B","explanation":"Given:  \u2192 P - 2g + 1 = g + 3p ......(1)  \u2192 P - 2 = 0 ......(2)   g is unknown   from 2; p = 0 + 2 = 2  Substitute for p = 2 in (i)  2 - 2g + 1 = g + 3(2)  3 - 2g = g + 6  -3g = 3  -g = 1  \u2234 g = -1","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2008>9","subject":"Mathematics","year":"2008","type":"Objective","topic":"ALGEBRAIC PROCESSES : ALGEBRAIC FRACTIONS","question":"Simplify:1/x + 1/yx + y","images":[],"options":{"A":"1x + y","B":"1xy","C":"x + y","D":"xy"},"answer":"B","explanation":"Given: To simplify:1/x + 1/yx + y  \u2234y + xxy\u00d71 y + x  =  1xy","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2008>10","subject":"Mathematics","year":"2008","type":"Objective","topic":"NUMBER AND NUMERATION : LAWS OF INDICES","question":"Simplify: &#179&radic;27x3y9&nbsp;","images":[],"options":{"A":"9xy3","B":"3xy6","C":"3xy3","D":"9y3"},"answer":"C","explanation":"Given: To simplify  &#179&radic;27x3y9&nbsp;   = &#179&radic;27&nbsp; \u00d7 &#179&radic;x3&nbsp; \u00d7 &#179&radic;y9&nbsp;   = (27)1/3 \u00d7 (x3)1/3 \u00d7 (y9)1/3   = 3 \u00d7 x \u00d7 y3 = 3xy3","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2008>11","subject":"Mathematics","year":"2008","type":"Objective","topic":"ALGEBRAIC PROCESSES : FORMULATION AND EVALUATION OF ALGEBRAIC PROCESSES","question":"Giventhatx=2andy=-14,evaluatex2y - 2xy5","images":[],"options":{"A":"0","B":"1/5","C":"1","D":"2"},"answer":"A","explanation":"Given: x = 2 and y = -1/4  \u2234x2y-2xy5  =(2)2 (-1/4) - 2(2) (-1/4)5  =-1+15=05=0","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2008>12","subject":"Mathematics","year":"2008","type":"Objective","topic":"ALGEBRAIC PROCESSES : EXPANSION AND FACTORISATION","question":"Factorize 5y2 + 2ay - 3a2","images":[],"options":{"A":"(a - y)(5y - 3a)","B":"(y - a)(5y - 3a)","C":"(y - a)(5y + 3a)","D":"(y + a)(5y - 3a)"},"answer":"D","explanation":"Given: To factorize 5y2 + 2ay - 3a2  1. Multiply 5y2 by -3a2 to get -15a2y2  2. Look for two factors of -15a2y2 such that when added together, you will get +2ay.  \u2192 By inspection, the factors are (-3ay) and (+5ay) since -3ay + 5ay = 2ay  3. Then: 5y2 + 2ay - 3a2 becomes:  5y2 + 5ay - 3ay - 3a2   = 5y(y + a) - 3a(y + a)   = (5y - 3a)(y + a)","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2008>13","subject":"Mathematics","year":"2008","type":"Objective","topic":"ALGEBRAIC PROCESSES : LINEAR EQUATIONS IN ONE VARIABLE","question":"If 4y is 9 greater than the sum of y and 3x, by how much is y greater than x?","images":[],"options":{"A":"3","B":"6","C":"9","D":"12"},"answer":"A","explanation":"Given:  1. 4y - (y + 3x) = 9  2. y - x is unknown  from (1), we have:  4y - y - 3x = 9   = 3y - 3x = 9  divide through by 3  y - x = 3  \u2234 y - x = 3","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2008>14","subject":"Mathematics","year":"2008","type":"Objective","topic":"ALGEBRAIC PROCESSES : ALGEBRAIC FRACTIONS","question":"Ifp=35&radic; qr &nbsp;,expressqintermsofpandr.","images":[],"options":{"A":"925pr2","B":"925p2r","C":"259p2r","D":"259pr2"},"answer":"C","explanation":"Given:  P=35&radic;qr&nbsp;  Square both sides  p2=(35)2\u00d7qr  p2=925\u00d7qr  p2=9q25r  25r \u00d7 p2 = 9q  q=25p2r9","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2008>15","subject":"Mathematics","year":"2008","type":"Objective","topic":"ALGEBRAIC PROCESSES : EXPANSION AND FACTORISATION","question":"Simplify:2x2 - 5x - 124x2 - 9","images":[],"options":{"A":"x + 42x + 3","B":"x + 42x - 3","C":"x - 42x + 3","D":"x - 42x - 3"},"answer":"D","explanation":"Given: To simplify:2x2 - 5x - 124x2 - 9  2x2 - 5x - 12 will be factorized to give (2x + 3)(x - 4)  4x2 - 9 will be factorized to give (2x - 3)(2x + 3)  2x2 - 5x - 124x2 - 9=(2x + 3)(x - 4)(2x - 3)(2x + 3)=x - 42x - 3","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2008>16","subject":"Mathematics","year":"2008","type":"Objective","topic":"TRIGONOMETRY : SINE, COSINE AND TANGENT OF AN ANGLE","question":"In the diagram, \u2220QPR = 90\u00b0. If q2 = 25 - r2, find the value of p.","images":["data:image/png;base64,"],"options":{"A":"3","B":"4","C":"5","D":"6"},"answer":"C","explanation":"Given: From the diagram, to find the value of P   \u2192 q2 = 25 - r2 ......(1)  Using pythagoras theorem:  P2 = q2 + r2 ......(2)  Substitute for q2 = 25 - r2  P2 = 25 - r2 + r2  P2 = 25  P = &radic;25&nbsp; = \u00b15","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2008>17","subject":"Mathematics","year":"2008","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"\u2220PQR is a sector of a circle centre O, radius 4cm. If \u2220PQR = 30\u00b0, find, correct to 3 significant figures, the area of sector \u2220POR.  [Take \u03c0 = 22/7]","images":[],"options":{"A":"4.19cm2","B":"8.38cm2","C":"10.5cm2","D":"20.9cm2"},"answer":"A","explanation":"Given:  Angle \u03b8, at the point O of the sector = 30\u00b0  Radius, r of the circle = 4cm  Area, A of the sector is unknown   Recall that: A=\u03b8360\u00d7\u03c0r2  A=30360\u00d7227\u00d716  A=112\u00d7227\u00d716  A=43\u00d7227=8821=4.19cm2","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2008>18","subject":"Mathematics","year":"2008","type":"Objective","topic":"MENSURATION : VOLUMES","question":"If the volume of a cube is 343cm3, find the length of its side.","images":[],"options":{"A":"3cm","B":"6cm","C":"7cm","D":"8cm"},"answer":"C","explanation":"Given:  The volume, V of a cube = 343cm3  Recall that: the volume , V of a cube = l3  V = l3  343 = l3   l = 7cm","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2008>19","subject":"Mathematics","year":"2008","type":"Objective","topic":"MENSURATION : LENGTHS AND PERIMETERS","question":"In the diagram, PQRS is a rhombus. /PR/ = 10cm and /QS/ = 24cm.  Calculate the perimeter of the rhombus.","images":["data:image/png;base64,"],"options":{"A":"34cm","B":"52cm","C":"56cm","D":"96cm"},"answer":"B","explanation":"Given: The diagram in the question  1. The length of PR = 10cm and that of QS = 24cm  2. The two diagonals will intersect at right-angles at a point O  3. |OQ| = |OS| and |OP| = |OR|  4. All the sides in a rhombus are equal.  Extract a right-angled triangle from the four that we have within the rhombus.    |QS| = 24cm; |OS| = 24/2 = 12cm  |PR| = 10cm, |OR| = 10/2 = 5cm  Let |SR| = P  From Pythagoras theorem:  P2 = 122 + 52  P2 = 144 + 25  P2 = 169  P = &radic;169&nbsp;  P = \u00b113cm (the positive will be taken)  The perimeter of the rhombus = |PS| + |SR| + |QR| + |PQ|   P = 13 + 13 + 13 + 13    = 52cm","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2008>20","subject":"Mathematics","year":"2008","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"In the diagram /PQ/ = /QR/ and /PR/ = /RS/ = /SP/. Calculate the side of \u2220 QRS.","images":["data:image/png;base64,"],"options":{"A":"150\u00b0","B":"120\u00b0","C":"90\u00b0","D":"60\u00b0"},"answer":"C","explanation":"Given: The diagram  \u0394PRS is equilateral (all the angles 2nd sides are equal)   \u2234 In \u0394PRS, \u2220P = \u2220R = \u2220S = 60\u00b0  \u2220Q + \u2220S = 180\u00b0 (opposite angles of a cyclic quadrilateral )  \u2234 60\u00b0 + \u2220S = 180\u00b0  \u2220S = 120\u00b0   \u0394PQR is isosceles;  In \u0394PQR, \u2220P = \u2220R (Base angles of isosceles)  \u2220Q = 120\u00b0  120\u00b0 + \u2220P + \u2220R = 180\u00b0 (sum of \u2220 in a triangle)  since \u2220P = \u2220R  120\u00b0 + \u2220P + \u2220P = 180\u00b0  \u22202P = 60\u00b0  \u2220P = 30\u00b0  \u2234 \u2220R = 30\u00b0  \u2220QRS = \u2220R of \u0394PQR + \u2220R of \u0394PSR   = 30\u00b0 + 60\u00b0    = 90\u00b0","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2008>21","subject":"Mathematics","year":"2008","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"In the figure shown, PQS is a straight line. What is the value of \u2220PRQ?","images":["data:image/png;base64,"],"options":{"A":"128\u00b0","B":"108\u00b0","C":"98\u00b0","D":"78\u00b0"},"answer":"D","explanation":"Given: The diagram  \u2220 RQS + \u2220PQR = 180\u00b0 (angle on a straight line)  148\u00b0 + &radic;PQR&nbsp; = 180\u00b0  \u2220 PQR = 32\u00b0  \u2220 PRQ + 70\u00b0 + 32\u00b0 = 180\u00b0 (sum of angles in a triangle)  \u2220 PRQ + 102\u00b0 = 180\u00b0  \u2220 PRQ = (180 - 102)\u00b0  \u2220 PRQ = 78\u00b0","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2008>22","subject":"Mathematics","year":"2008","type":"Objective","topic":"PLANE GEOMETRY : ANGLES AND INTERCEPTS ON PARALLEL LINES","question":"In the diagram, PQ // RS, QU // PT and \u2220 PSR = 42\u00b0. Find angle x.","images":["data:image/png;base64,"],"options":{"A":"84\u00b0","B":"48\u00b0","C":"42\u00b0","D":"32\u00b0"},"answer":"C","explanation":"From the diagram, \u2220P = 42\u00b0 (alternate angles)   since P is alternate to S  \u2220 P = X (corresponding angles)  \u2234 X = 42\u00b0","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2008>23","subject":"Mathematics","year":"2008","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"The angles of a quadrilateral are (x + 10)\u00b0, 2y\u00b0, 90\u00b0 and (100 - y)\u00b0. Find y in terms of x.","images":[],"options":{"A":"y = 160 + x","B":"y = 100 + x","C":"y = 160 - x","D":"y = x - 100"},"answer":"C","explanation":"Given: (x + 10)\u00b0, 2y\u00b0, 90\u00b0 and (100 - y)\u00b0 as the angles in a quadrilateral.  Recall: The sum of angles in a quadrilateral = 360\u00b0  \u2234 x + 10 + 2y + 90 + 100 - y = 360\u00b0  x + y + 200 = 360\u00b0  x + y = 160\u00b0  y = 160 - x","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2008>24","subject":"Mathematics","year":"2008","type":"Objective","topic":"PLANE GEOMETRY : TRIANGLES AND POLYGONS","question":"In the figure /PX/ = /XQ/, PQ // YZ and XY // QR. What is the ratio of the area of XYZQ to the area of \u0394YZR?","images":["data:image/png;base64,"],"options":{"A":"1 : 2","B":"2 : 1","C":"1 : 3","D":"3 : 1"},"answer":"B","explanation":"XYZQ is parallelogram /YZ/ = /XQ/  let the area of XYZQ = A1  Area of triangle XY = area of triangle  = A1 + A2  Area of PQRarea of PXY=(PQPX)=(PRXY)2  AA2=41=21  A = 4A2 = recall A = A1 + 2A  A1 = 4A2 - 2A2  A1/A2 = 2  A1A2 = 2:1","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2008>25","subject":"Mathematics","year":"2008","type":"Objective","topic":"PLANE GEOMETRY : CIRCLES","question":"In the diagram, O is the centre of the circle and PQRS is a cyclic quadrilateral. Find the value of x.","images":["data:image/png;base64,"],"options":{"A":"25\u00b0","B":"65\u00b0","C":"115\u00b0","D":"139\u00b0"},"answer":"B","explanation":"Given: The diagram  \u2220 PQR + 65\u00b0 = 180\u00b0 (angle on a straight line)  \u2220 PQR = 180 - 65 = 115  \u2220 PQR + x = 180\u00b0 (opposite angles of a cyclic quadrilateral)  \u2234 115 + x = 180\u00b0  x = 65\u00b0.","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2008>26","subject":"Mathematics","year":"2008","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"If x\u00b0 is obtuse, which of the following is true?","images":[],"options":{"A":"x > 90","B":"180","C":"x","D":"90"},"answer":"D","explanation":"Obtuse angles are angles that are greater than 90\u00b0 and less than 180\u00b0  \u2234 x > 90 and x  That us 90","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2008>27","subject":"Mathematics","year":"2008","type":"Objective","topic":"TRIGONOMETRY : SINE, COSINE AND TANGENT OF AN ANGLE","question":"If tan x = 1, evaluate sin x + cos x, leaving your answer in the surd form.","images":[],"options":{"A":"2&radic;2&nbsp;","B":"12&radic;2&nbsp;","C":"&radic;2&nbsp;","D":"2"},"answer":"C","explanation":"Given:  tan x = 1  x = tan-1(1)  x = 45\u00b0  Recall that: tan\u03b8=sin\u03b8cos\u03b8  tan x =sin xcos x  tan45\u00b0=sin45\u00b0cos45\u00b0 = 1  sin x + cos x = sin 45\u00b0 + cos 45\u00b0  =1&radic;2&nbsp;+1&radic;2&nbsp;=&radic;2&nbsp;","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2008>28","subject":"Mathematics","year":"2008","type":"Objective","topic":"TRIGONOMETRY : SINE, COSINE AND TANGENT OF AN ANGLE","question":"If cos (x + 25)\u00b0 = sin45\u00b0, find the value of x.","images":[],"options":{"A":"20","B":"30","C":"45","D":"60"},"answer":"A","explanation":"Given:  cos(x + 25)\u00b0 = sin45\u00b0   Recall that:  cos\u03b8 = sin(90 - \u03b8)Also, sin45\u00b0 = cos(90 - 45)\u00b0  \u2234 cos(x + 25)\u00b0 = sin45\u00b0   = cos(x + 25)\u00b0 = cos(90 - 45)\u00b0  x + 25 = 45  x = 20\u00b0","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2008>29","subject":"Mathematics","year":"2008","type":"Objective","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"The graph below shows the pattern of a town in a year. What is the average monthly rainfall?","images":["data:image/png;base64,"],"options":{"A":"2.70cm","B":"2.71cm","C":"2.72cm","D":"2.78cm"},"answer":"B","explanation":"Given: The graph  Theaveragemonthlyrainfall=sum of the amounts ofrainfallthe total months  \u2234Meanmonthlyrainfall,=0.5 + 1 + 2 + 3 + 4 + 4 + 4.5 + 3 + 5 + 5 + 0.512  =32.512=2.708cm\u22482.71cm","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2008>30","subject":"Mathematics","year":"2008","type":"Objective","topic":"NUMBER AND NUMERATION : LAWS OF INDICES","question":"If 2n = 128, find the value of (2n - 1)(5n - 2)","images":[],"options":{"A":"5(106)","B":"2(106)","C":"5(105)","D":"2(105)"},"answer":"D","explanation":"Given:  2n = 128  The value of (2n - 1)(5n - 2) is unknown  2n = 128; 128 = 27  \u2234 2n = 27  Equate the powers   n = 7   \u2234 (2n - 1)(5n - 2) = (27 - 1)(57 - 2)   = (26)(55)   = 2 \u00d7 25 \u00d7 55   = 2 \u00d7 (2 \u00d7 5)5   = 2 \u00d7 105 = 2(105)","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2008>31","subject":"Mathematics","year":"2008","type":"Objective","topic":"ALGEBRAIC PROCESSES : BINARY OPERATIONS","question":"If x \u03b1 (45 + 1/2 y), which of the following is true?","images":[],"options":{"A":"x varies directly as y","B":"x varies inversely as y","C":"x is partly constant and partly varies as y","D":"x varies jointly as 45 and directly as y"},"answer":"C","explanation":"x \u03b1 (45 + 1/2 y) implies x is partly constant and partly varies as y.","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2008>32","subject":"Mathematics","year":"2008","type":"Objective","topic":"NUMBER AND NUMERATION : LOGARITHMS","question":"Simplifylog &radic;8&nbsp;log4 - log2","images":[],"options":{"A":"23","B":"1/2 log2","C":"32","D":"log 2"},"answer":"C","explanation":"Given:  Simplifylog &radic;8&nbsp;log4 - log2  Let the logarithms be in base 10  \u2234log&radic;8&nbsp;log4 - log2=log81/2log22 - log21  =1/2 log82log2 - log2=1/2 log232log2 - log2  =3/2 log2log2=32","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2008>33","subject":"Mathematics","year":"2008","type":"Objective","topic":"NUMBER AND NUMERATION : LOGICAL REASONING","question":"Every staff in an office owns either a Mercedes and/or a Toyota car. 20 own Mercedes, 15 own Toyota and 5 own both. How many staff are there in the office?","images":[],"options":{"A":"25","B":"30","C":"35","D":"45"},"answer":"B","explanation":"Let M = Mercedes owners   T = Toyota owners  U = All members of staff  M \u2229 T = staff that own both brands of cars  M \u222a T = staff that own toyota or mercedes  U = M + T - M \u2229 T  U = 20 + 15 - 5  U = 30","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2008>34","subject":"Mathematics","year":"2008","type":"Objective","topic":"ALGEBRAIC PROCESSES : FORMULATION AND EVALUATION OF ALGEBRAIC PROCESSES","question":"A train travels 60km in M minutes. If its average speed is 400km per hour, find the value of M.","images":[],"options":{"A":"15","B":"12","C":"10","D":"9"},"answer":"D","explanation":"Given:  The distance travelled by the train = 60km  Thetimetakentocoverthedistance=Mminutes=M60hours  The average speed = 400km per hour   Recall:Averagespeed=Total distance travelledTotal time taken  400=60\u00f7M60  400=60\u00d760M  4=36M  4M = 36   M = 9","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2008>35","subject":"Mathematics","year":"2008","type":"Objective","topic":"PLANE GEOMETRY : CIRCLES","question":"An arc of a circle, radius 14cm, is 18.33cm long. Calculate, to the nearest degree, the angle which the arc subtends at the centre of the circle.  [Take \u03c0 = 22/7]","images":[],"options":{"A":"11\u00b0","B":"20\u00b0","C":"22\u00b0","D":"75\u00b0"},"answer":"D","explanation":"Given:   The radius, r of the circle = 14cm  The length, l of the circle = 18.33cm  The angle, \u03b8 subtended by the arc is unknown   Recall: l=\u03b8360\u00d72\u03c0r  18.33=\u03b8360\u00d72\u00d7227\u00d714  18.33 \u00d7 360 \u00d7 7 = \u03b8 \u00d7 2 \u00d7 22 \u00d7 14   \u03b8=18.33\u00d7252044\u00d714=18.33\u00d718044=3299.444   = 74.98\u00b0 \u2248 75 to the nearest degree.","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2008>36","subject":"Mathematics","year":"2008","type":"Objective","topic":"MENSURATION : VOLUMES","question":"What is the length of an edge of a cube whose total surface area is X cm2 and whose volume is X/2 cm3?","images":[],"options":{"A":"3","B":"6","C":"9","D":"12"},"answer":"D","explanation":"Given:  Edges of the cube = x cm  The number of edges in a cube = 6  Edge = 4 \u00d7 6 = 24  \u2234 24/2 = 12","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2008>37","subject":"Mathematics","year":"2008","type":"Objective","topic":"PLANE GEOMETRY : CIRCLES","question":"XY is a chord of circle centre O and radius 7cm. The chord XY which is 8cm long subtends an angle of 120\u00b0 at the centre of the circle. Calculate the perimeter of the minor segment. [Take \u03c0 = 22/7]","images":[],"options":{"A":"14.67cm","B":"22.67cm","C":"29.33cm","D":"37.33cm"},"answer":"B","explanation":"Diagramatically, we have;    The perimeter of the segment = Length of the arc + Length of the chord  Lengthofthearc=\u03b8360\u00d72\u03c0r=120360\u00d72\u00d7227\u00d77=14.67cm  Length of the chord = 8cm  Perimeter of the segment = 14.67 + 8 = 22.67cm","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2008>38","subject":"Mathematics","year":"2008","type":"Objective","topic":"PLANE GEOMETRY : TRIANGLES AND POLYGONS","question":"If the perimeter of \u0394PQR in the diagram is 24cm, what is the area of \u0394PRS?","images":["data:image/png;base64,"],"options":{"A":"19.5cm2","B":"15.0cm2","C":"13.0cm2","D":"9.3cm2"},"answer":"B","explanation":"Given:  The perimeter of \u0394PQR = 24cm  \u2234 24 = |PQ| + |QR| + |RP|  24 = 14 + |RP|  24 = 14 + |RP|  |RP| = 10cm .......(1)  Let the point of intersection of the vertical line that runs through S and PR be O  \u2234 |PR| = |OP| + |OR| = 10cm from ......(1)  From pythagora's theorem  |OR|2  + |OS|2 = |RS|2   \u2234 |OR|2 + 32 = (6.5)2  |OR|2 + 9 = 42.25  |OR|2 = 33.25  |OR| = &radic;33.25&nbsp;  |OR| = 5.77cm  since: |OP| + |OR| = 10  \u2234 |OP| + 5.77 = 10  |OP| = 4.23  It should be noted that  Area of \u0394PRS = Area of \u0394ROS + Area of \u0394 POS  Areaof\u0394PRS=12\u00d74.23\u00d73+12\u00d75.77\u00d73  =32(10)=15cm2","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2008>39","subject":"Mathematics","year":"2008","type":"Objective","topic":"ALGEBRAIC PROCESSES : ALGEBRAIC FRACTIONS","question":"Ifp=12and1p - 1=2p + x,findthevalueofx.","images":[],"options":{"A":"-212","B":"-112","C":"112","D":"212"},"answer":"B","explanation":"Given:   P=12and1p-1=2P+x  substituteforP=12in1p - 1=2p + x  Wehave:11/2 - 1=21/2 + x  1-1/2=21/2 + x  -2=21/2 + x  -1 -2x = 2  -3 = 2x;  x=-32=-112","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2008>40","subject":"Mathematics","year":"2008","type":"Objective","topic":"ALGEBRAIC PROCESSES : QUADRATIC EQUATIONS","question":"Find the quadratic equation whose roots are c and -c.","images":[],"options":{"A":"x2 + c2 = 0","B":"x2 - c2 = 0","C":"x2 + 2cx + c2 = 0","D":"x2 - 2cx + c2 = 0"},"answer":"B","explanation":"Given:  Two roots of a quadratic equation (c and -c)  The quadratic equation  = (x + c)(x - c)   = x2 - c2 = 0","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2008>41","subject":"Mathematics","year":"2008","type":"Objective","topic":"ALGEBRAIC PROCESSES : LINEAR INEQUALITIES","question":"Solvetheinequality1-2x-13","images":[],"options":{"A":"x23","B":"x-23","C":"x>23","D":"x>-23"},"answer":"C","explanation":"Given: The inequality  1-2x-13  1 + 1/3  4/3  4  46x  x>23","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2008>42","subject":"Mathematics","year":"2008","type":"Objective","topic":"ALGEBRAIC PROCESSES : LINEAR INEQUALITIES","question":"For what range of values of x is 1/2x + 2 \u2265 2x - 1?","images":[],"options":{"A":"x \u2264 2","B":"x \u2265 2","C":"x \u2264 3","D":"x \u2265 3"},"answer":"A","explanation":"Given:  12x+2\u22652x-1  12x-2x\u2265-1-2  -32x\u2265-3  x \u2264 2","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2008>43","subject":"Mathematics","year":"2008","type":"Objective","topic":"ALGEBRAIC PROCESSES : LINEAR INEQUALITIES","question":"Which of the number lines below best represents the inequality -3 \u2265 x \u2264 4?","images":["data:image/png;base64,","data:image/png;base64,","data:image/png;base64,","data:image/png;base64,"],"options":{"A":"","B":"","C":"","D":""},"answer":"C","explanation":"- This best represents the inequality -3 \u2264 x  - The shaded point of -3 means x = -3 (other options have this)  - The line is moving towards the right, i.e x \u2265 -3 (other options have this)  - The unshaded point of it means x  4; but since the line stops at 4, it means x","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2008>44","subject":"Mathematics","year":"2008","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"In the diagram, PX is a tangent to the circle and RST is an equilateral triangle. Calculate \u2220PTS","images":["data:image/png;base64,"],"options":{"A":"60\u00b0","B":"90\u00b0","C":"120\u00b0","D":"150\u00b0"},"answer":"C","explanation":"Since \u0394RST is an equilateral triangle, all its angles = 60\u00b0  \u2220RST = \u2220RTP = 60\u00b0  \u2220PTS = \u2220RTP + \u2220 RTS  \u2220 PTS = 60\u00b0 + 60\u00b0   = 129\u00b0","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2008>45","subject":"Mathematics","year":"2008","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"In the diagram, \u2220QPR = 60\u00b0, \u2220PQR = 50\u00b0, \u2220QRS = 2x\u00b0, \u2220SRP = 3x\u00b0, \u2220UQP = y\u00b0 and RS //TU.  Calculate y.","images":["data:image/png;base64,"],"options":{"A":"102\u00b0","B":"78\u00b0","C":"70\u00b0","D":"60\u00b0"},"answer":"A","explanation":"In \u0394 PQR  \u2220P + \u2220Q + \u2220R)  = 180\u00b0 (sum of angles in a triangle)  60\u00b0 + 50\u00b0 + 5x = 180\u00b0  110\u00b0 + 5x = 180\u00b0  5x = 70\u00b0  x = 14\u00b0  Also, \u2220RQT = 2x (alternate angles)  \u2220RQT = 2(14) = 28\u00b0  \u2234 \u2220RQT + 50\u00b0 + y = 180\u00b0 (sum of angles on a straight line)  28 + 50 + y = 180\u00b0  y = 180 - 78    = 102\u00b0","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2008>46","subject":"Mathematics","year":"2008","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"In the diagram, find the size of the angle marked a\u00b0.","images":["data:image/png;base64,"],"options":{"A":"60\u00b0","B":"80\u00b0","C":"120\u00b0","D":"160\u00b0"},"answer":"B","explanation":"From the diagram arc, RT subtends at 260\u00b0 at the centre.  \u2234 It (arc RT) will subtend  280/2 at other points on the circumference e.g point S.  Angle subtended at S by arc RT = 140\u00b0  \u2220ROT + 280 = 360\u00b0 (angle at a point)  \u2220ROT = 80\u00b0 ROTS is a quadrilateral. The total angles within it = 360\u00b0  \u2234 60\u00b0 + 80\u00b0 + 140\u00b0 + a = 360\u00b0  280\u00b0 + a = 360\u00b0  a = 80\u00b0","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2008>47","subject":"Mathematics","year":"2008","type":"Objective","topic":"STATISTICS AND PROBABILITY. : PROBABILITY","question":"Given the sets A = {2, 4, 6, 8} and B = {2, 3, 5, 9}, use the information to answer this question.    If a number is selected at random from set B, what is the probability that the number is prime?","images":[],"options":{"A":"1","B":"3/4","C":"1/2","D":"1/4"},"answer":"B","explanation":"Given: Two sets, A and B  A = {2, 4, 6, 8} and B = {2, 3, 5, 9}  The probability that a number selected from B is prime =   Number of prime numbers in BTotal numbers inB=34   Note that we have three prime numbers out of the four elements in set B.","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2008>48","subject":"Mathematics","year":"2008","type":"Objective","topic":"STATISTICS AND PROBABILITY. : PROBABILITY","question":"Given the sets A = {2, 4, 6, 8} and B = {2, 3, 5, 9}, use the information to answer this question.  If a number is picked at random from each of the two sets, what is the probability that their product is odd?","images":[],"options":{"A":"1","B":"3/4","C":"1/4","D":"0"},"answer":"D","explanation":"It should be noted that in set A, we have just even  numbers, since even number multiplied by an odd number will always give an even number, it implies that we will never have an odd number from the multiplication.","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2008>49","subject":"Mathematics","year":"2008","type":"Objective","topic":"STATISTICS AND PROBABILITY. : PROBABILITY","question":"Given the sets A = {2, 4, 6, 8} and B = {2, 3, 5, 9}, use the information to answer this question.  If a number is picked at random from each of the two sets, what is the probability that their difference is 6 or 7?","images":[],"options":{"A":"1/256","B":"1/16","C":"1/8","D":"1/2"},"answer":"C","explanation":"Take each number in A and B and find the difference.  A = {2, 4, 6, 8} and B = {2, 3, 5, 9}  { |2 - 2|, |2 - 3|, |2 - 5|, |2 - 9|} = {0, 1, 3, 7}  { |4 - 2|, |4 - 3|, |4 - 5|, |4 - 9|} = {2, 1, 1, 5}  { |6 - 2|, |6 - 3|, |6 - 5|, |6 - 9|} = {4, 3, 1, 3}  { |8 - 2|, |8 - 3|, |8 - 5|, |8 - 9|} = {6, 5, 3, 1}  The total outcomes = 16  Number of outcomes equal to 6 or 7 = 2  Prob.of6or7=216=18","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2008>50","subject":"Mathematics","year":"2008","type":"Objective","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"Find the mean deviation of these numbers: 10, 12, 14, 15, 17, 19.","images":[],"options":{"A":"2.5","B":"2.6","C":"2.7","D":"2.8"},"answer":"A","explanation":"M.D = ?   10, 12, 14, 15, 17, 19  Recall,MeanDeviation=\u2211/(x - x\u0304)/\u2211f  whereMean,x\u0304=\u2211fx\u2211f  \u2211fx = 10 + 12 + 14 + 15 + 17 + 19 = 87  \u2211f = 6  \u2234x\u0304=876=14.5  M.D=(10 - 14.5) + (12 - 14.5) + (14 - 14.5) + (15 - 14.5) + (17 - 14.5) + (19 - 14.5)6  M.D=4.5 + 2.5 + 0.5 + 0.5 + 2.5 + 4.56  M.D=156=2.5","marks":"1","difficulty":"1"}];